import { createContext, useState, useEffect } from "react";
import { getMe } from "../api/auth";
import { saveToken, getToken, saveUser, getUser, clearAuthData } from "../utils/localStorage";
import { useNavigate } from "react-router-dom";

// ============================================================================
// CONSTANTS
// ============================================================================

const ROUTES = {
  STUDENT_DASHBOARD: "/dashboard",
  TEACHER_DASHBOARD: "/teacher/dashboard",
  LOGIN: "/login",
};

const ROLES = {
  STUDENT: "student",
  TEACHER: "teacher",
};

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

/**
 * Détermine le rôle de l'utilisateur à partir des données utilisateur
 * @param {object} userData - Données utilisateur
 * @returns {string} - 'student' ou 'teacher'
 */
const getUserRole = (userData) => {
  console.log("🔍 getUserRole() - Analyse des données utilisateur:");
  console.log("  - userData:", userData);
  console.log("  - userData.role:", userData?.role);
  console.log("  - Type de userData.role:", typeof userData?.role);

  if (!userData) {
    console.warn("⚠️ Aucun userData fourni, utilisation du rôle par défaut (student)");
    return ROLES.STUDENT;
  }

  // Vérifier si le rôle est peuplé (objet avec name)
  if (userData.role && typeof userData.role === "object") {
    const roleName = userData.role.name || userData.role.type;
    console.log("  - roleName détecté:", roleName);

    if (roleName) {
      const normalizedRole = roleName.toLowerCase();
      console.log("  - normalizedRole:", normalizedRole);

      // Détection des rôles teacher
      if (normalizedRole.includes("teacher")) {
        console.log("✅ Rôle TEACHER détecté!");
        return ROLES.TEACHER;
      }

      // Détection des rôles student
      if (normalizedRole.includes("student")) {
        console.log("✅ Rôle STUDENT détecté!");
        return ROLES.STUDENT;
      }

      console.warn(`⚠️ Rôle non reconnu: "${roleName}", utilisation par défaut (student)`);
      return ROLES.STUDENT;
    }
  }

  // Si le rôle n'est pas peuplé (ID numérique)
  if (userData.role && typeof userData.role === "number") {
    console.error(
      "❌ Rôle non peuplé! Le rôle est un ID (nombre), pas un objet. Il faut utiliser getMe() pour obtenir le rôle peuplé."
    );
    console.error("  - userData.role (ID):", userData.role);
  }

  // Si le rôle est undefined ou null
  if (!userData.role) {
    console.error("❌ Rôle non défini dans userData!");
  }

  // Fallback basé sur des champs métier
  if (userData.isTeacher) {
    console.log("✅ Rôle TEACHER détecté via isTeacher flag!");
    return ROLES.TEACHER;
  }

  // Par défaut, retourner student
  console.warn("⚠️ Rôle non détecté, utilisation par défaut (student)");
  return ROLES.STUDENT;
};

/**
 * Redirige l'utilisateur vers le dashboard approprié selon son rôle
 * @param {string} role - Rôle de l'utilisateur ('student' ou 'teacher')
 * @param {Function} navigate - Fonction de navigation de react-router-dom
 */
const redirectToDashboard = (role, navigate) => {
  console.log("🧭 redirectToDashboard() - DÉBUT");
  console.log("  - Rôle reçu:", role);
  console.log("  - ROLES.STUDENT:", ROLES.STUDENT);
  console.log("  - ROLES.TEACHER:", ROLES.TEACHER);
  console.log("  - Comparaison role === ROLES.STUDENT:", role === ROLES.STUDENT);
  console.log("  - Comparaison role === ROLES.TEACHER:", role === ROLES.TEACHER);
  console.log("  - navigate disponible:", typeof navigate === "function" ? "✅" : "❌");

  if (typeof navigate !== "function") {
    console.error("❌ navigate n'est pas une fonction! Utilisation de window.location.href");
    // Fallback: utiliser window.location.href
    if (role === ROLES.TEACHER) {
      window.location.href = ROUTES.TEACHER_DASHBOARD;
    } else {
      window.location.href = ROUTES.STUDENT_DASHBOARD;
    }
    return;
  }

  if (role === ROLES.STUDENT) {
    console.log("👨‍🎓 Redirection vers dashboard étudiant:", ROUTES.STUDENT_DASHBOARD);
    navigate(ROUTES.STUDENT_DASHBOARD);
  } else if (role === ROLES.TEACHER) {
    console.log("👨‍🏫 Redirection vers dashboard professeur:", ROUTES.TEACHER_DASHBOARD);
    navigate(ROUTES.TEACHER_DASHBOARD);
  } else {
    console.warn("⚠️ Rôle inconnu:", role, "- Redirection par défaut vers dashboard étudiant");
    navigate(ROUTES.STUDENT_DASHBOARD);
  }
  
  console.log("✅ redirectToDashboard() - navigate() appelé");
};

// ============================================================================
// CONTEXT
// ============================================================================

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const navigate = useNavigate();

  // Vérification que navigate est disponible
  useEffect(() => {
    console.log("🔵 AuthProvider - Composant monté");
    console.log("  - navigate disponible:", typeof navigate === "function" ? "✅" : "❌");
    console.log("  - navigate:", navigate);
  }, [navigate]);

  // ============================================================================
  // EFFECTS
  // ============================================================================

  /**
   * Vérifie l'authentification au chargement de l'application
   * Ne redirige PAS automatiquement pour éviter les boucles de redirection
   * La redirection se fait uniquement lors du login
   */
  useEffect(() => {
    const checkAuth = async () => {
      const token = getToken();
      const savedUser = getUser();

      if (token) {
        try {
          // Récupérer les données utilisateur complètes depuis le serveur
          const userData = await getMe();
          setUser(userData);
          // Ne pas rediriger ici pour éviter les boucles
          // La redirection se fait uniquement lors du login
        } catch (error) {
          console.warn("Token invalide ou expiré, déconnexion...");
          clearAuthData();
          setUser(null);
        }
      } else if (savedUser) {
        // Nettoyer les données si pas de token mais utilisateur en cache
        clearAuthData();
      }

      setIsLoading(false);
    };

    checkAuth();
  }, []);

  // ============================================================================
  // AUTH FUNCTIONS
  // ============================================================================

  /**
   * Gère la connexion de l'utilisateur et redirige vers le dashboard approprié
   * @param {object} data - Données de connexion { jwt, user }
   */
  const loginUser = async (data) => {
    console.log("=".repeat(50));
    console.log("🔐 loginUser() - DÉBUT DE LA CONNEXION");
    console.log("=".repeat(50));
    console.log("  - Données reçues:", data);

    // Validation des données
    if (!data || !data.jwt || !data.user) {
      console.error("❌ Données d'authentification invalides");
      return;
    }

    console.log("  - Token JWT:", data.jwt ? "✅ Présent" : "❌ Absent");
    console.log("  - User data:", data.user);
    console.log("  - User.role (depuis /auth/local):", data.user.role, "Type:", typeof data.user.role);

    // Sauvegarder le token et les données utilisateur de base
    saveToken(data.jwt);
    saveUser(data.user);
    console.log("✅ Token et données utilisateur sauvegardés");

    try {
      // IMPORTANT: La réponse de /auth/local ne contient PAS le rôle peuplé
      // Elle retourne user.role comme un ID (nombre), pas comme un objet avec name
      // Il faut appeler getMe() pour obtenir les données complètes avec populate=role
      console.log("📡 Appel à getMe() pour récupérer les données complètes avec le rôle peuplé...");
      const userData = await getMe();
      console.log("✅ Données utilisateur complètes récupérées:", userData);
      console.log("  - userData.role:", userData.role);
      console.log("  - Type de userData.role:", typeof userData.role);
      
      setUser(userData);

      // Déterminer le rôle et rediriger
      console.log("🔍 Détermination du rôle...");
      const role = getUserRole(userData);
      console.log("🎯 Rôle final déterminé:", role);
      console.log("🧭 Redirection vers le dashboard approprié...");
      console.log("  - navigate disponible:", typeof navigate === "function" ? "✅" : "❌");
      console.log("  - navigate:", navigate);
      
      redirectToDashboard(role, navigate);
      
      console.log("✅ loginUser() - Redirection déclenchée");
    } catch (error) {
      console.error("❌ Erreur lors de la récupération des données utilisateur:", error);
      console.error("  - Message d'erreur:", error.message);
      console.error("  - Stack:", error.stack);
      
      // En cas d'erreur, utiliser les données de base et rediriger vers dashboard étudiant par défaut
      console.warn("⚠️ Utilisation des données de base (rôle peut ne pas être détecté)");
      setUser(data.user);
      navigate(ROUTES.STUDENT_DASHBOARD);
    }
  };

  /**
   * Déconnecte l'utilisateur et redirige vers la page de connexion
   */
  const logout = () => {
    console.log("🚪 Déconnexion");
    clearAuthData();
    setUser(null);
    navigate(ROUTES.LOGIN);
  };

  return (
    <AuthContext.Provider value={{ user, loginUser, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};
